const input = $input.item.json;
const prevNode = $('Extraire infos WhatsApp').item.json;

let reponseIA = '';
try {
  reponseIA = input.output || input.text || '';
} catch (e) {
  reponseIA = "Merci pour ton message ! On revient vers toi très vite.";
}

// Nettoyer salutations et signatures résiduelles
reponseIA = reponseIA
  .replace(/^(Bonjour|Salut|Hello|Hey|Coucou)\s+\w+[,!]?\s*/i, '')
  .replace(/\n*(Cordialement|À bientôt|À très vite|Bien à toi|Stella des Ombres|L'équipe Les Ombres)[^\n]*$/gi, '')
  .trim();

return {
  json: {
    to: prevNode.from,
    messageWhatsApp: reponseIA,
    phoneNumber: prevNode.phoneNumber,
    profileName: prevNode.profileName,
    phoneNumberId: prevNode.phoneNumberId
  }
};
